```csharp
using System;
using System.Collections.Generic;

public class NQueens
{
    private int n;
    private int[] queens; // queens[row] = col;
    private List<int[]> solutions;

    public NQueens(int n)
    {
        this.n = n;
        this.queens = new int[n];
        this.solutions = new List<int[]>();
    }

    public List<int[]> SolveNQueens()
    {
        SolveNQueensUtil(0);
        return solutions;
    }

    private void SolveNQueensUtil(int row)
    {
        if (row == n)
        {
            // Found a solution
            solutions.Add((int[])queens.Clone()); // Add a copy to the list
            return;
        }

        for (int col = 0; col < n; col++)
        {
            if (IsSafe(row, col))
            {
                queens[row] = col;
                SolveNQueensUtil(row + 1);
            }
        }
    }

    private bool IsSafe(int row, int col)
    {
        for (int i = 0; i < row; i++)
        {
            // Check same column
            if (queens[i] == col)
            {
                return false;
            }

            // Check diagonals
            if (Math.Abs(queens[i] - col) == row - i)
            {
                return false;
            }
        }

        return true;
    }

    public void PrintSolutions()
    {
        foreach (var solution in solutions)
        {
            PrintSolution(solution);
            Console.WriteLine();
        }
    }

    private void PrintSolution(int[] solution)
    {
        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < n; j++)
            {
                if (solution[i] == j)
                {
                    Console.Write("Q ");
                }
                else
                {
                    Console.Write(". ");
                }
            }
            Console.WriteLine();
        }
    }

    public static void Main(string[] args)
    {
        int n = 8; // Change this value for different board sizes
        NQueens nQueens = new NQueens(n);
        List<int[]> solutions = nQueens.SolveNQueens();

        Console.WriteLine($"Found {solutions.Count} solutions for N = {n}");
        nQueens.PrintSolutions();

        // Example of accessing the first solution:
        if (solutions.Count > 0)
        {
            int[] firstSolution = solutions[0];
            Console.WriteLine("\nFirst Solution (Column positions of queens in each row):");
            Console.WriteLine(string.Join(", ", firstSolution));
        }
    }
}
```

