Il rompicapo noto come problema delle N regine è un problema che implica il posizionamento di N regine degli scacchi su una scacchiera N×N in modo tale che nessuna coppia di regine sia in grado di minacciarsi a vicenda. Ciò significa che una soluzione valida deve garantire che nessuna coppia di regine sia posizionata sulla stessa riga, colonna o diagonale della scacchiera.

```csharp
// Codice C# per il posizionamento di n regine
using System;

class GfG
{
    static void breakLine()
    {
        Console.Write("\n---------------------------------\n");
    }

    // dimensione massima della scacchiera
    static int MAX = 10;

    // array per memorizzare i posizionamenti delle regine
    static int[] arr = new int[MAX];

    // variabile per contare il numero di soluzioni trovate
    static int no;

    // funzione ricorsiva per trovare le soluzioni
    static void nQueens(int k, int n)
    {
        // prova tutte le posizioni possibili per la regina nella riga corrente
        for (int i = 1; i <= n; i++)
        {
            // controlla se la regina può essere posizionata nella posizione corrente
            if (canPlace(k, i))
            {
                // posiziona la regina nella posizione corrente
                arr[k] = i;

                // se tutte le regine sono posizionate, visualizza la soluzione
                if (k == n)
                {
                    display(n);
                }
                else
                {
                    // prova ricorsivamente a posizionare le regine rimanenti
                    nQueens(k + 1, n);
                }
            }
        }
    }

    // funzione di supporto per controllare se la regina può essere posizionata nella posizione corrente
    static bool canPlace(int k, int i)
    {
        for (int j = 1; j <= k - 1; j++)
        {
            // controlla se la regina è già posizionata nella stessa colonna o diagonale
            if (arr[j] == i || (Math.Abs(arr[j] - i) == Math.Abs(j - k)))
            {
                return false;
            }
        }
        return true;
    }

    // funzione per visualizzare la soluzione
    static void display(int n)
    {
        breakLine();
        Console.Write("Disposizione No. " + ++no);
        breakLine();

        for (int i = 1; i <= n; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                // stampa '_' per la cella vuota e 'Q' per la cella con la regina
                if (arr[i] != j)
                {
                    Console.Write("\t_");
                }
                else
                {
                    Console.Write("\tQ");
                }
            }
            Console.WriteLine("");
        }

        breakLine();
    }

    // Codice driver per inizializzare il problema e chiamare la funzione ricorsiva
    public static void Main(String[] args)
    {
        int n = 4; // dimensione della scacchiera
        nQueens(1, n);
    }
}
```

