L'idea è generare tutti i numeri primi minori o uguali al numero dato N usando il Crivello di Eratostene. Una volta generati tutti questi numeri primi, li memorizziamo tutti in un array e stampiamo tutti i numeri primi che occupano posizioni di numero primo. Ecco un'implementazione in Python:

```
# Programma Python per stampare superprimi minori o uguali a n.

# Genera tutti i numeri primi minori di n usando il Crivello di Eratostene.
def sieve(n):
    is_prime = [True for i in range(n+1)]
    is_prime[0] = False
    is_prime[1] = False

    for p in range(2,n+1):
        if is_prime[p]:
            for i in range(2*p, n+1, p):
                is_prime[i] = False

    return is_prime

def super_primes(n):
    # Genera tutti i numeri primi
    is_prime = sieve(n)

    # Memorizza tutti i numeri primi in un array
    primes = [i for i, prime in enumerate(is_prime) if prime]
    primes = [0] + primes
    for i, p in enumerate(primes):
        if is_prime[i]:
            yield p
```

L'algoritmo di Dijkstra è molto simile all'algoritmo di Prim per l'albero di copertura minimo. Come l'MST di Prim, genera un SPT (albero del percorso più breve) con una data sorgente come radice. Mantiene due insiemi, un insieme contiene i vertici inclusi nell'albero del percorso più breve, l'altro insieme include i vertici non ancora inclusi nell'albero del percorso più breve. Ad ogni passo dell'algoritmo, trova un vertice che si trova nell'altro insieme (insieme non ancora incluso) e ha una distanza minima dalla sorgente.

```c
// Il programma mira a implementare l'algoritmo del percorso più breve a sorgente singola di Dijkstra in linguaggio C.
// Il programma utilizza una matrice di adiacenza come rappresentazione del grafo

#include <limits.h>
#include <stdbool.h>
#include <stdio.h>

// Il numero di vertici presenti in un grafo.
#define V 9

// Una funzione utilizzata per identificare il vertice con il valore di distanza più piccolo
// tra un insieme di vertici che non sono ancora stati inclusi nell'albero del percorso più breve.
int findMinDistance(int dist[], bool sptSet[])
{
    // Inizializza il valore minimo
    int min = INT_MAX, min_index;

    for (int v = 0; v < V; v++)
        if (sptSet[v] == false && dist[v] <= min)
            min = dist[v], min_index = v;
    return min_index;
}

// Una funzione di utilità per stampare l'array delle distanze costruito
// array
void printSolution(int dist[])
{
    printf("Vertice \t\t Distanza dalla Sorgente\n");
    for (int i = 0; i < V; i++)
        printf("%d \t\t\t\t %d\n", i, dist[i]);
}

// una funzione che applica l'algoritmo di Dijkstra per trovare il percorso più breve tra
// un singolo nodo di origine e tutti gli altri nodi in un grafo. Il grafo è rappresentato utilizzando
// una matrice di adiacenza.
void dijkstra(int graph[V][V], int src)
{
    int dist[V];
    bool processed[V];
    int i, u, v;

    // Inizializza tutte le distanze come infinite e processed come false
    for (i = 0; i < V; i++) {
        dist[i] = INT_MAX;
        processed[i] = false;
    }

    // La distanza del vertice di origine da se stesso è sempre 0
    dist[src] = 0;

    // Trova il percorso più breve per tutti i vertici
    for (i = 0; i < V - 1; i++) {
        // Scegli il vertice con la distanza minima dall'insieme di vertici non ancora elaborati
        u = -1;
        for (i = 0; i < V; i++) {
            if (!processed[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
        }

        // Contrassegna il vertice scelto come elaborato
        processed[u] = true;

        // Aggiorna il valore dist dei vertici adiacenti al vertice scelto
        for (v = 0; v < V; v++) {
            if (graph[u][v] != 0 && !processed[v]) {
                int new_dist = dist[u] + graph[u][v];
                if (new_dist < dist[v]) {
                    dist[v] = new_dist;
                }
            }
        }
    }

    // Stampa l'array delle distanze costruito
    printSolution(dist);
}


int main()
{
    /*  Crea il grafo di esempio */
    int graph[V][V] = { { 0, 4, 0, 0, 0, 0, 0, 8, 0 },
                        { 4, 0, 8, 0, 0, 0, 0, 11, 0 },
                        { 0, 8, 0, 7, 0, 4, 0, 0, 2 },
                        { 0, 0, 7, 0, 9, 14, 0, 0, 0 },
                        { 0, 0, 0, 9, 0, 10, 0, 0, 0 },
                        { 0, 0, 4, 14, 10, 0, 2, 0, 0 },
                        { 0, 0, 0, 0, 0, 2, 0, 1, 6 },
                        { 8, 11, 0, 0, 0, 0, 1, 0, 7 },
                        { 0, 0, 2, 0, 0, 0, 6, 7, 0 } };

        // Chiamata di funzione
        dijkstra(graph, 0);

        return 0;
}
