```java
import java.util.*;

class Edge {
    int src, dest, weight;

    Edge(int src, int dest, int weight) {
        this.src = src;
        this.dest = dest;
        this.weight = weight;
    }
}

class Graph {
    int V; // Number of vertices/cities
    List<Edge> edges;

    Graph(int V) {
        this.V = V;
        this.edges = new ArrayList<>();
    }

    void addEdge(int src, int dest, int weight) {
        edges.add(new Edge(src, dest, weight));
        edges.add(new Edge(dest, src, weight)); // Assuming undirected graph
    }

    // Kruskal's Algorithm implementation using Union-Find
    int minCostConnectCitiesKruskal() {
        edges.sort(Comparator.comparingInt(e -> e.weight)); // Sort edges by weight

        int[] parent = new int[V];
        for (int i = 0; i < V; i++) {
            parent[i] = i; // Initialize each vertex as its own parent
        }

        int minCost = 0;
        int edgeCount = 0;

        for (Edge edge : edges) {
            int rootSrc = find(parent, edge.src);
            int rootDest = find(parent, edge.dest);

            if (rootSrc != rootDest) { // If not in the same set, add to MST
                union(parent, rootSrc, rootDest);
                minCost += edge.weight;
                edgeCount++;
            }

            if (edgeCount == V - 1) { // Optimization: MST is complete
                break;
            }
        }

        return minCost;
    }

    // Find the root of a vertex (path compression)
    int find(int[] parent, int i) {
        if (parent[i] == i) {
            return i;
        }
        return parent[i] = find(parent, parent[i]); // Path compression
    }

    // Union two sets by rank (union by rank could be added for further optimization)
    void union(int[] parent, int x, int y) {
        int xroot = find(parent, x);
        int yroot = find(parent, y);
        parent[xroot] = yroot;
    }

    //Prim's Algorithm implementation
    int minCostConnectCitiesPrim() {
        int minCost = 0;
        PriorityQueue<Edge> pq = new PriorityQueue<>(Comparator.comparingInt(e -> e.weight));
        boolean[] visited = new boolean[V];

        // Start from the first city (vertex 0)
        pq.add(new Edge(-1, 0, 0)); // Add a dummy edge with weight 0 to start from city 0

        while (!pq.isEmpty()) {
            Edge current = pq.poll();
            int u = current.dest; //Get the node we are expanding from

            if (visited[u]) continue;  //If the node is already visited, go next

            visited[u] = true;
            minCost += current.weight;

            // Add adjacent edges to the priority queue
            for (Edge edge : edges) {
                if (edge.src == u && !visited[edge.dest]) {
                    pq.add(edge);
                }
            }
        }

        return minCost;
    }

    public static void main(String[] args) {
        int V = 4; // Number of cities
        Graph graph = new Graph(V);

        // Example edges and their weights (distances between cities)
        graph.addEdge(0, 1, 10);
        graph.addEdge(0, 2, 6);
        graph.addEdge(0, 3, 5);
        graph.addEdge(1, 3, 15);
        graph.addEdge(2, 3, 4);


        System.out.println("Minimum cost to connect all cities (Kruskal): " + graph.minCostConnectCitiesKruskal());
        System.out.println("Minimum cost to connect all cities (Prim): " + graph.minCostConnectCitiesPrim());

    }
}
