        this.src = src;
        this.dest = dest;
        this.weight = weight;
    }
}

class Graph {
    int V; // Numero di vertici/città
    List<Edge> edges;

    Graph(int V) {
        this.V = V;
        this.edges = new ArrayList<>();
    }

    void addEdge(int src, int dest, int weight) {
        edges.add(new Edge(src, dest, weight));
        edges.add(new Edge(dest, src, weight)); // Assumendo un grafo non diretto
    }

    // Implementazione dell'algoritmo di Kruskal utilizzando Union-Find
    int minCostConnectCitiesKruskal() {
        edges.sort(Comparator.comparingInt(e -> e.weight)); // Ordina gli archi in base al peso

        int[] parent = new int[V];
        for (int i = 0; i < V; i++) {
            parent[i] = i; // Inizializza ogni vertice come genitore di se stesso
        }

        int minCost = 0;
        int edgeCount = 0;

        for (Edge edge : edges) {
            int rootSrc = find(parent, edge.src);
            int rootDest = find(parent, edge.dest);

            if (rootSrc != rootDest) { // Se non sono nello stesso insieme, aggiungi all'MST
                union(parent, rootSrc, rootDest);
                minCost += edge.weight;
                edgeCount++;
            }

            if (edgeCount == V - 1) { // Ottimizzazione: l'MST è completo
                break;
            }
        }

        return minCost;
    }

    // Trova la radice di un vertice (compressione del percorso)
    int find(int[] parent, int i) {
        if (parent[i] == i) {
            return i;
        }
        return parent[i] = find(parent, parent[i]); // Compressione del percorso
    }

    // Unisci due insiemi per rango (l'unione per rango potrebbe essere aggiunta per ulteriore ottimizzazione)
    void union(int[] parent, int x, int y) {
        int xroot = find(parent, x);
        int yroot = find(parent, y);
        parent[xroot] = yroot;
    }

       //Implementazione dell'algoritmo di Prim
    int minCostConnectCitiesPrim() {
        int minCost = 0;
        PriorityQueue<Edge> pq = new PriorityQueue<>(Comparator.comparingInt(e -> e.weight));
        boolean[] visited = new boolean[V];

        // Inizia dalla prima città (vertice 0)
        pq.add(new Edge(-1, 0, 0)); // Aggiungi un arco fittizio con peso 0 per iniziare dalla città 0

        while (!pq.isEmpty()) {
            Edge current = pq.poll();
            int u = current.dest; //Ottieni il nodo da cui ci stiamo espandendo

            if (visited[u]) continue;  //Se il nodo è già stato visitato, vai al successivo

            visited[u] = true;
            minCost += current.weight;

            // Aggiungi archi adiacenti alla PriorityQueue
            for (Edge edge : edges) {
                if (edge.src == u && !visited[edge.dest]) {
                    pq.add(edge);
                }
            }
        }

        return minCost;
    }


    public static void main(String[] args) {
        int V = 4; // Numero di città
        Graph graph = new Graph(V);

        // Esempio di archi e relativi pesi (distanze tra le città)
        graph.addEdge(0, 1, 10);
        graph.addEdge(0, 2, 6);
        graph.addEdge(0, 3, 5);
        graph.addEdge(1, 3, 15);
        graph.addEdge(2, 3, 4);


        System.out.println("Costo minimo per connettere tutte le città (Kruskal): " + graph.minCostConnectCitiesKruskal());
        System.out.println("Costo minimo per connettere tutte le città (Prim): " + graph.minCostConnectCitiesPrim());

    }
}
