L'obiettivo è stabilire il percorso più economico che colleghi tutte le città. Per raggiungere questo obiettivo, dobbiamo determinare l'albero di copertura minimo (MST) della mappa della città, trattando ogni città come un nodo sul grafico e tutte le strade danneggiate come archi. Il costo totale del percorso è la somma dei valori degli archi all'interno dell'albero di copertura minimo.

```java
// Codice Java per trovare il percorso
// di costo minimo per collegare tutte le città
import java.util.* ;

class GFG{

    // Funzione per trovare il nodo di valore minimo
    // tra i nodi che non sono ancora inclusi in MST

    static int minNode(int n, int keyvals[], boolean mstset[])
    {
        int min_val = Integer.MAX_VALUE;
        int min_index = 0;

        // Cicla attraverso tutti i valori dei nodi, 
        // che non sono ancora inclusi in MST e trova quello di valore minimo.
        for(int i = 0; i < n; i++)
        {
            if (mstset[i] == false && keyvals[i] < min_val)
            {
                min_val = keyvals[i];
                min_index = i;
            }
        }
        return min_index;
    }

    // Funzione per trovare l'MST e
    // il costo dell'MST.
    static void findCost(int n, int city[][])
    {

        // Array per memorizzare i nodi padre.
        int parent[] = new int[n];

        // Array per memorizzare il valore chiave di ogni nodo.
        int keyvals[] = new int[n];

        // Array booleano per indicare se un nodo è incluso in MST o meno.
        boolean mstset[] = new boolean[n];

        // Imposta tutti i valori chiave su infinito e nessuno dei nodi è incluso in MST.
        for(int i = 0; i < n; i++)
        {
            keyvals[i] = Integer.MAX_VALUE;
            mstset[i] = false;
        }

        // Inizia a trovare l'MST dal nodo 0.
        // Il padre del nodo 0 è nessuno e viene impostato su -1.
        // Il valore chiave o il costo minimo per raggiungere il nodo 0 dal nodo 0 è 0.
        parent[0] = -1;
        keyvals[0] = 0;

        // Trova i restanti n-1 nodi di MST.
        for(int i = 0; i < n - 1; i++)
        {    
            // Per prima cosa trova il nodo minimo tra i nodi che non sono ancora inclusi in MST.
            int u = minNode(n, keyvals, mstset);

            // Includi l'u-esimo nodo in MST.
            mstset[u] = true;

            // Aggiorna i valori dei nodi vicini di u che non sono ancora inclusi in MST.
            for(int v = 0; v < n; v++)
            {
                if (city[u][v] > 0 && mstset[v] == false && city[u][v] < keyvals[v])
                {
                    keyvals[v] = city[u][v];
                    parent[v] = u;
                }
            }
        }

        // Trova il costo sommando i valori degli archi di MST.
        int cost = 0;
        for(int i = 1; i < n; i++)
            cost += city[parent[i]][i];

        System.out.println(cost);
    }

    // Codice driver
    public static void main(String args[])
    {

        // Input 1
        int n1 = 5;
        int city1[][] = { { 0, 1, 2, 3, 4 },
                        { 1, 0, 5, 0, 7 },
                        { 2, 5, 0, 6, 0 },
                        { 3, 0, 6, 0, 0 },
                        { 4, 7, 0, 0, 0 } };

        findCost(n1, city1);

        // Input 2
        int n2 = 6;
        int city2[][] = { { 0, 1, 1, 100, 0, 0 },
                        { 1, 0, 1, 0, 0, 0 },
                        { 1, 1, 0, 0, 0, 0 },
                        { 100, 0, 0, 0, 2, 2 },
                        { 0, 0, 0, 2, 0, 2 },
                        { 0, 0, 0, 2, 2, 0 } };

        findCost(n2, city2);

    }
}
```

